+	}
+
+	payload, err := json.Marshal(map[string]string{"sub": subject, "email": email})
+	if err != nil {
+		t.Fatalf("marshal payload: %v", err)
+	}
+
+	return base64.RawURLEncoding.EncodeToString(header) + "." + base64.RawURLEncoding.EncodeToString(payload) + "."
+}
